const EXCEPTION_MARKERS: &str = "[TEST] gdt=ok, [TEST] idt=ok, [TEST] irq=ok, [TEST] exception=ok, cr2_present=, cr2_offset=0x, cr3_offset=0x, rflags=0x, interrupts_enabled=, present=, [TEST] pagefault=ok";
const TIMER_MARKERS: &str = "[TEST] gdt=ok, [TEST] idt=ok, [TEST] irq=ok, [TEST] exception=ok, timer setup=pit, timer tick 1, timer tick 2, timer delayed-log, [TEST] sleep=ok, timer tick 3, [TEST] timer=ok";

pub(super) const fn markers(smoke: SmokeKind) -> &'static str {
    match smoke {
        SmokeKind::Boot => BOOT_MARKERS,
        SmokeKind::Panic => PANIC_MARKERS,
        SmokeKind::Exception => EXCEPTION_MARKERS,
        SmokeKind::Timer => TIMER_MARKERS,
    }
}
